import jwt
from datetime import datetime, timedelta

def generate_jwt(user_id, role):
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': int(datetime.utcnow().timestamp()) + 3600  # expire in 1 hour
    }
    
    secret_key = 'your-secret-key-here'
    token = jwt.encode(payload, secret_key, algorithm='HS256')
    return token

def verify_jwt(token):
    try:
        payload = jwt.decode(token, 'your-secret-key-here', algorithms=['HS256'])
        return payload['user_id'], payload['role']
    except jwt.ExpiredSignatureError:
        print("Signature has expired. Please log in again.")
    except jwt.InvalidTokenError:
        print("Invalid token. Please try logging in again.")

# Example usage
user_id = 123
role = 'admin'
token = generate_jwt(user_id, role)
print(token)

user_id_verified, role_verified = verify_jwt(token)
print(f"User ID: {user_id_verified}, Role: {role_verified}")